+// splitCompoundShellAware splits a command on compound separators (;, &&, ||, &)
+// while respecting shell quoting rules. Separators inside quotes are not split.
+func splitCompoundShellAware(cmd string) []string {
+	var segments []string
+	var current strings.Builder
+	inSingleQuote := false
+	inDoubleQuote := false
+	escaped := false
+	runes := []rune(cmd)
+
+	for i := 0; i < len(runes); i++ {
+		r := runes[i]
+
+		// Handle escape sequences
+		if escaped {
+			current.WriteRune(r)
+			escaped = false
+			continue
+		}
+
+		if r == '\\' && !inSingleQuote {
+			current.WriteRune(r)
+			escaped = true
+			continue
+		}
+
+		// Handle quote state changes
+		if r == '\'' && !inDoubleQuote {
+			inSingleQuote = !inSingleQuote
+			current.WriteRune(r)
+			continue
+		}
+
+		if r == '"' && !inSingleQuote {
+			inDoubleQuote = !inDoubleQuote
+			current.WriteRune(r)
+			continue
+		}
+
+		// Check for compound separators only when outside quotes
+		if !inSingleQuote && !inDoubleQuote {
+			// Check for && or ||
+			if i+1 < len(runes) {
+				if (r == '&' && runes[i+1] == '&') || (r == '|' && runes[i+1] == '|') {
+					seg := strings.TrimSpace(current.String())
+					if seg != "" {
+						segments = append(segments, seg)
+					}
+					current.Reset()
+					i++ // Skip the second character of && or ||
+					continue
+				}
+			}
+
+			// Check for ; or single &
+			if r == ';' || r == '&' {
+				seg := strings.TrimSpace(current.String())
+				if seg != "" {
+					segments = append(segments, seg)
+				}
+				current.Reset()
+				continue
+			}
+		}
+
+		current.WriteRune(r)
+	}
+
+	// Add the last segment
+	seg := strings.TrimSpace(current.String())
+	if seg != "" {
+		segments = append(segments, seg)
+	}
+
+	return segments
+}
